#!/usr/bin/env python3
"""Debug the _header template processing."""

from neurodocker.reproenv.renderers import DockerRenderer
from neurodocker.reproenv.state import _TemplateRegistry
from neurodocker.reproenv.template import Template

def test_template_structure():
    """Check the structure of the _header template."""

    # Get the header template
    header_dict = _TemplateRegistry.get('_header')
    template = Template(header_dict)

    print("Main template attributes:")
    for attr in dir(template):
        if not attr.startswith('_') or attr in ['_template']:
            print(f"  {attr}: {getattr(template, attr, 'N/A')}")

    print("\nSource template attributes:")
    if template.source:
        for attr in dir(template.source):
            if not attr.startswith('_') or attr in ['_template']:
                print(f"  {attr}: {getattr(template.source, attr, 'N/A')}")

        print(f"\nSource template _template attribute: {getattr(template.source, '_template', 'NO _template')}")
        if hasattr(template.source, '_template'):
            parent = template.source._template
            print(f"  Parent template name: {getattr(parent, 'name', 'NO NAME')}")

if __name__ == "__main__":
    test_template_structure()

